const input = $input.first().json;
const body = input.body || input;
const taskType = body.task_type || "translation";
const sourceText = body.source_text || "";
const targetLanguage = body.target_language || "English";
const customInstructions = body.custom_instructions || "";
const round = body._round || 1;
const maxRounds = body._max_rounds || 10;
const previousResult = body._previous_result || null;
const previousFeedback = body._previous_feedback || null;

// Input validation
if (!sourceText || sourceText.trim().length === 0) {
  return [{ json: { error: "source_text is required and cannot be empty", status: "validation_error" } }];
}

let systemPrompt = "";
let userPrompt = "";

if (taskType === "translation") {
  systemPrompt = "You are a professional translator. Translate the given text into " + targetLanguage + ". Preserve tone, meaning, and formatting. " + customInstructions;
  if (previousResult && previousFeedback) {
    userPrompt = "ROUND " + round + ": Your previous translation was rejected.\n\nOriginal text:\n" + sourceText + "\n\nYour previous attempt:\n" + previousResult + "\n\nReviewer feedback:\n" + previousFeedback + "\n\nPlease produce an improved translation addressing all feedback.";
  } else {
    userPrompt = "Translate the following text into " + targetLanguage + ":\n\n" + sourceText;
  }
} else if (taskType === "code") {
  systemPrompt = "You are an expert software engineer. Write clean, efficient, well-tested code. " + customInstructions;
  if (previousResult && previousFeedback) {
    userPrompt = "ROUND " + round + ": Your previous code was rejected.\n\nOriginal request:\n" + sourceText + "\n\nYour previous attempt:\n" + previousResult + "\n\nReviewer feedback:\n" + previousFeedback + "\n\nPlease produce improved code addressing all feedback.";
  } else {
    userPrompt = sourceText;
  }
} else {
  systemPrompt = "You are a helpful AI assistant. " + customInstructions;
  if (previousResult && previousFeedback) {
    userPrompt = "ROUND " + round + ": Your previous output was rejected.\n\nOriginal request:\n" + sourceText + "\n\nYour previous attempt:\n" + previousResult + "\n\nReviewer feedback:\n" + previousFeedback + "\n\nPlease produce an improved response addressing all feedback.";
  } else {
    userPrompt = sourceText;
  }
}

return [{ json: {
  task_type: taskType,
  source_text: sourceText,
  target_language: targetLanguage,
  custom_instructions: customInstructions,
  system_prompt: systemPrompt,
  user_prompt: userPrompt,
  round: round,
  max_rounds: maxRounds
} }];

const grounding = $input.first().json;
const execution = $input.first().json;

// Extract result from Ollama response â€” handle both success and error
let executionResult;
try {
  const ollamaResponse = $("Agent 2: Execution (Mistral Small)").first().json;
  executionResult = ollamaResponse.message ? ollamaResponse.message.content : "ERROR: No content in Ollama response";
} catch (e) {
  executionResult = "ERROR: Failed to get execution result: " + e.message;
}

// Get grounding context
const ground = $("Agent 1: Grounding").first().json;

const baseReview = {
  task_type: ground.task_type,
  source_text: ground.source_text,
  target_language: ground.target_language,
  custom_instructions: ground.custom_instructions,
  execution_result: executionResult,
  round: ground.round,
  max_rounds: ground.max_rounds
};

return [
  { json: { ...baseReview, reviewer: "quality_qwen", reviewer_index: 0 } },
  { json: { ...baseReview, reviewer: "resolution_qwen", reviewer_index: 1 } },
  { json: { ...baseReview, reviewer: "quality_mistral", reviewer_index: 2 } },
  { json: { ...baseReview, reviewer: "resolution_mistral", reviewer_index: 3 } }
];

const reviews = $input.all();
const grounding = $("Prepare 4 Reviews").first().json;
const reviewerNames = ["Quality (Qwen)", "Resolution (Qwen)", "Quality (Mistral)", "Resolution (Mistral)"];

let allApproved = true;
let feedbackList = [];
let parsedReviews = [];

for (let i = 0; i < reviews.length; i++) {
  const raw = reviews[i].json.message ? reviews[i].json.message.content : "{}";
  let parsed;
  try {
    // Non-greedy: find the LAST complete JSON object (most likely the structured review)
    const jsonMatches = raw.match(/\{[^{}]*(?:\{[^{}]*\}[^{}]*)*\}/g);
    const lastJson = jsonMatches ? jsonMatches[jsonMatches.length - 1] : raw;
    parsed = JSON.parse(lastJson);
  } catch (e) {
    // If JSON parse fails, try to extract verdict from plain text
    const hasApprove = raw.toUpperCase().includes("APPROVE");
    const scoreMatch = raw.match(/(\d+)\s*\/\s*10|score[:\s]*(\d+)/i);
    const score = scoreMatch ? parseInt(scoreMatch[1] || scoreMatch[2]) : 0;
    parsed = {
      verdict: hasApprove && score >= 7 ? "APPROVE" : "REJECT",
      score: score,
      feedback: "Auto-parsed from non-JSON response: " + raw.substring(0, 300)
    };
  }

  parsedReviews.push({
    reviewer: reviewerNames[i] || "Reviewer " + i,
    verdict: parsed.verdict || "REJECT",
    score: parsed.score || 0,
    feedback: parsed.feedback || "No feedback"
  });

  if ((parsed.verdict || "").toUpperCase() !== "APPROVE") {
    allApproved = false;
    feedbackList.push("[" + reviewerNames[i] + "] " + (parsed.feedback || "Rejected without feedback"));
  }
}

const avgScore = parsedReviews.reduce(function(sum, r) { return sum + (r.score || 0); }, 0) / parsedReviews.length;

if (allApproved || grounding.round >= grounding.max_rounds) {
  return [{ json: {
    status: allApproved ? "approved" : "max_rounds_reached",
    final_result: grounding.execution_result,
    rounds_taken: grounding.round,
    average_score: Math.round(avgScore * 10) / 10,
    reviews: parsedReviews,
    task_type: grounding.task_type
  } }];
} else {
  return [{ json: {
    status: "rejected",
    loop_back: true,
    round: grounding.round,
    next_round: grounding.round + 1,
    execution_result: grounding.execution_result,
    combined_feedback: feedbackList.join("\n\n"),
    reviews: parsedReviews,
    average_score: Math.round(avgScore * 10) / 10,
    task_type: grounding.task_type,
    source_text: grounding.source_text,
    target_language: grounding.target_language,
    custom_instructions: grounding.custom_instructions,
    max_rounds: grounding.max_rounds
  } }];
}

const result = $input.first().json;
return [{ json: {
  status: result.status,
  result: result.final_result,
  rounds: result.rounds_taken,
  score: result.average_score,
  reviews: result.reviews
} }];
